import React, { useState } from 'react';

interface SkillGroupProps {
  title: string;
  icon: string;
  color: string;
  skills: string[];
}

const SkillGroup: React.FC<SkillGroupProps> = ({ title, icon, color, skills }) => {
  const [hovered, setHovered] = useState<number | null>(null);

  return (
    <div style={{
      marginBottom: 20,
      borderRadius: 2,
      overflow: 'hidden',
      border: '1px solid #ddd',
      boxShadow: '2px 2px 0 #c0c0c0',
    }}>
      {/* Header bar */}
      <div style={{
        background: color,
        padding: '10px 16px',
        display: 'flex',
        alignItems: 'center',
        gap: 10,
      }}>
        <span style={{
          fontSize: 22,
          background: 'rgba(255,255,255,0.2)',
          width: 36,
          height: 36,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          borderRadius: 2,
          flexShrink: 0,
        }}>{icon}</span>
        <span style={{
          color: '#fff',
          fontWeight: 'bold',
          fontSize: 13,
          letterSpacing: 0.5,
          textShadow: '0 1px 2px rgba(0,0,0,0.3)',
        }}>{title}</span>
      </div>

      {/* Skills */}
      <div style={{
        background: '#fafafa',
        padding: '12px 16px',
        display: 'flex',
        flexWrap: 'wrap',
        gap: 8,
      }}>
        {skills.map((s, i) => (
          <span
            key={i}
            onMouseEnter={() => setHovered(i)}
            onMouseLeave={() => setHovered(null)}
            style={{
              padding: '4px 12px',
              fontSize: 11,
              fontWeight: 'bold',
              letterSpacing: 0.3,
              cursor: 'default',
              transition: 'all 0.15s',
              background: hovered === i ? color : '#fff',
              color: hovered === i ? '#fff' : '#333',
              border: `1px solid ${color}`,
              boxShadow: hovered === i ? `0 2px 6px rgba(0,0,0,0.15)` : 'none',
              transform: hovered === i ? 'translateY(-1px)' : 'none',
            }}
          >{s}</span>
        ))}
      </div>
    </div>
  );
};

const groups = [
  {
    icon: '☁️', title: 'Cloud Platforms', color: '#0078d4',
    skills: ['AWS Cloud Practitioner', 'Azure AZ-900', 'Azure AZ-104', 'Microsoft Entra ID', 'Azure Active Directory'],
  },
  {
    icon: '🔒', title: 'Security & Compliance', color: '#c23b22',
    skills: ['ISC2 Certified in Cybersecurity', 'Microsoft Defender', 'Microsoft Purview', 'Security Incident Response'],
  },
  {
    icon: '💻', title: 'Endpoint & Device Management', color: '#107c10',
    skills: ['Microsoft Intune', 'SCCM', 'Knox Management', 'Flexera Snow', 'Windows', 'iOS', 'Linux'],
  },
  {
    icon: '📊', title: 'Microsoft 365 & Monitoring', color: '#d83b01',
    skills: ['Teams Admin', 'Exchange', 'Purview', 'AppDynamics', 'Zscaler ELK', 'Thousand Eyes'],
  },
  {
    icon: '🏢', title: 'Business Applications', color: '#5c2d91',
    skills: ['Microsoft FinOps', 'Dynamics 365 Retail', 'SAP C/4HANA', 'EFTPOS / POS Systems', 'Farmlands Pro'],
  },
  {
    icon: '⚙️', title: 'Scripting & Automation', color: '#005b70',
    skills: ['PowerShell', 'Active Directory', 'ITIL Service Management', 'License Management', 'Network Configuration'],
  },
];

const Skills: React.FC = () => (
  <div style={{ padding: '24px 28px', maxWidth: 780 }}>

    {/* Page header */}
    <div style={{
      marginBottom: 24,
      paddingBottom: 16,
      borderBottom: '3px solid #000080',
      display: 'flex',
      alignItems: 'flex-end',
      justifyContent: 'space-between',
    }}>
      <div>
        <h2 style={{ fontSize: 22, marginBottom: 4, color: '#000080' }}>Technical Skills</h2>
        <p style={{ fontSize: 11, color: '#666', margin: 0 }}>
          {groups.reduce((acc, g) => acc + g.skills.length, 0)} skills across {groups.length} categories
        </p>
      </div>
      <div style={{ display: 'flex', gap: 6 }}>
        {['☁️','🔒','💻','📊','🏢','⚙️'].map((e, i) => (
          <span key={i} style={{ fontSize: 18 }}>{e}</span>
        ))}
      </div>
    </div>

    {/* Two-column layout */}
    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
      {groups.map(g => (
        <SkillGroup key={g.title} {...g} />
      ))}
    </div>

  </div>
);

export default Skills;
